import TabButton from "./TabButton.jsx";
import { PROJECTS } from "../data.js";
import { useState } from "react";
import Section from "./Section.jsx";
import Tabs from "./Tabs.jsx";
import "./Projects.css";

export default function Projects() {
  const [selectedTopic, setSelectedTopic] = useState();

  function handleSelect(selectedButton) {
    setSelectedTopic(selectedButton);
  }

  let tabContent = <p>Please select a project.</p>;

  if (selectedTopic) {
    tabContent = (
      <div id="tab-content">
        <h3>{PROJECTS[selectedTopic].title}</h3>
        <p>{PROJECTS[selectedTopic].description}</p>
        <p>{PROJECTS[selectedTopic].skils}</p>
      </div>
    );
  }

  return (
    <Section title="Projects" id="projects">
      <Tabs
        buttons={
          <>
            <TabButton
              isSelected={selectedTopic === "SetCardGame"}
              onSelect={() => handleSelect("SetCardGame")}
            >
              Set Card Game
            </TabButton>
            <TabButton
              isSelected={selectedTopic === "ClientServer"}
              onSelect={() => handleSelect("ClientServer")}
            >
              Client Server
            </TabButton>
            <TabButton
              isSelected={selectedTopic === "shell"}
              onSelect={() => handleSelect("shell")}
            >
              Linux shell
            </TabButton>
            <TabButton
              isSelected={selectedTopic === "state"}
              onSelect={() => handleSelect("state")}
            >
              State
            </TabButton>
          </>
        }
      >
        {tabContent}
      </Tabs>
    </Section>
  );
}
